import Marquee from "react-fast-marquee";
import { motion } from "framer-motion";

const videoItems = [
  "/assets/videos/cooking.mp4",
  "/assets/videos/vid2.mp4",
  "/assets/videos/vid3.mp4",
  "/assets/videos/vid5.mp4",
  "/assets/videos/vid6.mp4"
];

const imageItems = [
  "/assets/amb.jpg",
  "/assets/apr.jpg",
  "/assets/ballent.jpg",
  "/assets/bl.jpg",
  "/assets/bn.jpg",
  "/assets/dj.jpg",
  "/assets/dri.jpg",
  "/assets/f1.jpg",
  "/assets/grp.jpg",
  "/assets/nod.jpg",
  "/assets/pic.jpg",
  "/assets/piz.jpg"
];

const MovingGallery = () => {
  return (
    <section className="py-16 md:py-24 bg-black overflow-hidden">
      <motion.div
        initial={{ opacity: 0, y: 30 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: true }}
        className="text-center mb-16"
      >
        <span className="font-accent text-gold text-sm tracking-[0.3em] uppercase">
          Why Choose Us
        </span>
        <h2 className="font-heading text-4xl md:text-5xl lg:text-6xl text-white mt-4">
          The Corridor Experience
        </h2>
      </motion.div>

      {/* Video Marquee - Portrait, No Gap */}
      <div className="mb-12">
        <Marquee speed={20} gradient={false} pauseOnHover>
          {videoItems.map((src, index) => (
            <div key={index} className="inline-block w-[200px] h-[350px] mx-1">
              <video
                src={src}
                className="w-full h-full object-cover rounded-xl shadow-xl"
                muted
                autoPlay
                loop
                playsInline
                preload="metadata"
              />
            </div>
          ))}
        </Marquee>
      </div>

      {/* Images Row 1 LTR */}
      <div className="mb-12">
        <Marquee speed={45} gradient={false} pauseOnHover>
          {imageItems.slice(0, 10).map((src, index) => (
            <motion.div
              key={index}
              className="inline-block w-[280px] h-[200px] mx-1 overflow-hidden rounded-lg shadow-lg"
              whileHover={{ scale: 1.05 }}
            >
              <img
                src={src}
                className="w-full h-full object-cover grayscale hover:grayscale-0 transition-all duration-300"
                loading="lazy"
              />
            </motion.div>
          ))}
        </Marquee>
      </div>

      {/* Images Row 2 RTL */}
      <div>
        <Marquee speed={45} direction="right" gradient={false} pauseOnHover>
          {imageItems.slice(0, 8).map((src, index) => (
            <motion.div
              key={"r" + index}
              className="inline-block w-[280px] h-[200px] mx-1 overflow-hidden rounded-lg shadow-lg"
              whileHover={{ scale: 1.05 }}
            >
              <img
                src={src}
                className="w-full h-full object-cover grayscale hover:grayscale-0 transition-all duration-300"
                loading="lazy"
              />
            </motion.div>
          ))}
        </Marquee>
      </div>
    </section>
  );
};

export default MovingGallery;
